        for i, line in enumerate(fh):
            try:
                o = json.loads(line)
            except:
                continue
            if o.get('type') == 'user':
                msg_count += 1
                m = o.get('message', {})
                c = m.get('content', '')
                text = ''
                if isinstance(c, str):
                    text = c
                elif isinstance(c, list):
                    for item in c:
                        if isinstance(item, dict) and item.get('type') == 'text':
                            text = item.get('text', '')
                            break
                if text and not text.startswith('<') and len(text) > 20:
                    if first_user is None:
                        first_user = text[:150]
                    last_user = text[:150]
